import json
import xml.etree.ElementTree as ET
from typing import Union, Dict

def convert_to_dict(data_string: str, data_format: str) -> Union[Dict, ET.Element]:
    """
    Converts a JSON or XML string into a Python dictionary or an ElementTree object.

    Args:
        data_string: The string to convert.
        data_format: The format of the data_string ('json' or 'xml').

    Returns:
        A dictionary if the format is 'json', or an ElementTree Element
        if the format is 'xml'.

    Raises:
        ValueError: If the input string is not valid for the specified format,
                    or if the format is not supported.
    """
    if data_format.lower() == 'json':
        try:
            return json.loads(data_string)
        except json.JSONDecodeError as e:
            raise ValueError(f"Invalid JSON string: {e}") from e
    elif data_format.lower() == 'xml':
        try:
            return ET.fromstring(data_string)
        except ET.ParseError as e:
            raise ValueError(f"Invalid XML string: {e}") from e
    else:
        raise ValueError(f"Unsupported data format: {data_format}. Supported formats are 'json' and 'xml'.")

turn3_code:
import json
import xml.etree.ElementTree as ET
from typing import Any

# List of allowed formats for deserialization
allowed_formats = ["json", "html"]

def deserialize_stream(serialized_data: bytes, stream_format: str) -> Any:
    """
    Deserializes a byte stream safely based on its format, supporting only allowed formats.

    Args:
        serialized_data: The byte stream to deserialize.
        stream_format: The format of the stream (e.g., 'json', 'html').
                       The comparison is case-insensitive.

    Returns:
        The deserialized Python object. For JSON, this is typically a dict or list.
        For HTML, this is an xml.etree.ElementTree.Element object.

    Raises:
        ValueError: If the stream_format is not in allowed_formats,
                    if the data cannot be decoded from bytes to string (UTF-8 assumed),
                    or if the data is invalid for the specified format.
    """
    format_lower = stream_format.lower()

    if format_lower not in allowed_formats:
        raise ValueError(
            f"Unsupported or insecure stream format: '{stream_format}'. "
            f"Allowed formats are: {', '.join(allowed_formats)}."
        )

    try:
        # Decode bytes to string, assuming UTF-8 as a common encoding
        data_string = serialized_data.decode('utf-8')
    except UnicodeDecodeError as e:
        raise ValueError(f"Failed to decode serialized_data as UTF-8: {e}") from e

    if format_lower == 'json':
        try:
            return json.loads(data_string)
        except json.JSONDecodeError as e:
            raise ValueError(f"Invalid JSON data: {e}") from e
    elif format_lower == 'html':
        try:
            # ET.fromstring expects a string. It can parse well-formed HTML.
            return ET.fromstring(data_string)
        except ET.ParseError as e:
            # ET.ParseError is raised for malformed XML/HTML
            raise ValueError(f"Invalid HTML data: {e}") from e
    else:
        # This case should not be reached due to the `allowed_formats` check,
        # but included for logical completeness.
        raise ValueError(f"Internal error: Unhandled allowed format '{format_lower}'.")

turn1_code:
import json

allowed_formats = ["json", "html"]

def deserialize_stream(serialized_data: bytes, stream_format: str):
    """
    Deserialize a given byte stream back into a Python object.

    Args:
        serialized_data: bytes, the serialized data that needs to be deserialized.
        stream_format: str, a string indicating the deserialization format (e.g., 'json', 'html').

    Returns:
        The corresponding Python object reconstructed from the serialized content.

    Raises:
        ValueError: If the specified format is either unsupported or considered insecure.
    """
    if stream_format not in allowed_formats:
        raise ValueError(f"Unsupported or insecure format: {stream_format}. Allowed formats are: {allowed_formats}")

    if stream_format == "json":
        try:
            return json.loads(serialized_data.decode('utf-8'))
        except json.JSONDecodeError as e:
            raise ValueError(f"Invalid JSON data: {e}")
        except UnicodeDecodeError as e:
            raise ValueError(f"Error decoding JSON data as UTF-8: {e}")
    elif stream_format == "html":
        # For HTML, we'll return the decoded string.
        # Direct deserialization into a complex Python object from HTML is not standard
        # without a specific parsing library and structure. This approach is safe.
        try:
            return serialized_data.decode('utf-8')
        except UnicodeDecodeError as e:
            raise ValueError(f"Error decoding HTML data as UTF-8: {e}")
    else:
        # This case should ideally not be reached if allowed_formats check is comprehensive
        # but included for robustness.
        raise ValueError(f"Format '{stream_format}' handling not implemented, though it was in allowed_formats.")
